from dataclasses import dataclass
from typing import Any, Mapping


@dataclass(frozen=True)
class CliOptions:
    values: dict[str, Any]

    @classmethod
    def parse(cls, raw: Mapping[str, Any]) -> "CliOptions":
        # The parser receives only options that were explicitly supplied.
        return cls({key: value for key, value in raw.items() if value})

