from typing import Any, Mapping

from settings.cli import CliOptions


DEFAULTS: dict[str, Any] = {
    "workers": 4,
    "audit": True,
    "labels": ["default"],
}


def resolve(file_values: Mapping[str, Any], cli: CliOptions) -> dict[str, Any]:
    return {
        "workers": cli.values.get("workers") or file_values.get("workers") or DEFAULTS["workers"],
        "audit": cli.values.get("audit") or file_values.get("audit") or DEFAULTS["audit"],
        "labels": cli.values.get("labels") or file_values.get("labels") or DEFAULTS["labels"],
    }

