from settings.cli import CliOptions
from settings.resolver import resolve


def test_truthy_command_values_override_the_site_file():
    cli = CliOptions.parse(
        {"workers": 8, "audit": True, "labels": ["canary"]}
    )
    result = resolve(
        {"workers": 12, "audit": True, "labels": ["west"]}, cli
    )

    assert result == {
        "workers": 8,
        "audit": True,
        "labels": ["canary"],
    }


def test_truthy_file_values_override_defaults_without_command_values():
    result = resolve(
        {"workers": 6, "audit": True, "labels": ["batch"]},
        CliOptions.parse({}),
    )

    assert result == {
        "workers": 6,
        "audit": True,
        "labels": ["batch"],
    }
